              {fieldsMeta.length > 0 && (
                <FilterConfigDialog
                  open={filterDialogOpen}
                  onOpenChange={setFilterDialogOpen}
                  availableFields={fieldsMeta}
                  selectedKeys={selectedFilterKeys}
                  onApply={(keys) => {
